using System.Net;
using System.Net.Http;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// [BREAKING CHANGE 1 — ValidateScopes] .NET 9 enables ValidateScopes in
// development by default. A scoped service (IUserService) captured inside a
// singleton factory will now throw InvalidOperationException at startup.
// Fix: register CacheService as scoped so the lifetime matches.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// [BREAKING CHANGE 2 — SocketsHttpHandler] .NET 9 HttpClientFactory uses
// SocketsHttpHandler as the default primary handler. The previous cast to
// HttpClientHandler throws InvalidCastException at runtime.
// Fix: use ConfigurePrimaryHttpMessageHandler with an explicit handler.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler
    {
        UseCookies = false
    });

// [BREAKING CHANGE 3 — Header redaction] .NET 9 HttpClientFactory now redacts
// ALL header values in Trace-level logs by default. To keep visibility into the
// non-sensitive headers you were logging for debugging, allowlist them explicitly.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(header =>
        header != "X-Request-Id"
        && header != "X-Forwarded-For"
        && header != "X-Forwarded-Proto"));

// [BREAKING CHANGE 4 — Forwarded Headers] .NET 9 ForwardedHeadersMiddleware
// ignores X-Forwarded-* headers from proxies not in KnownProxies/KnownNetworks.
// Add your reverse-proxy IP addresses so headers are processed.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(IPAddress.Parse("127.0.0.1"));
});

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

