1. using System.Net;
2. using System.Net.Http;
3. using Microsoft.AspNetCore.HttpOverrides;
4. 
5. var builder = WebApplication.CreateBuilder(args);
6. builder.Services.AddScoped<IUserService, UserService>();
7. // [BREAKING CHANGE 1 — ValidateScopes] .NET 9 enables ValidateScopes in
8. // development by default. A scoped service (IUserService) captured inside a
9. // singleton factory will now throw InvalidOperationException at startup.
10. // Fix: register CacheService as scoped so the lifetime matches.
11. builder.Services.AddScoped<ICacheService>(sp =>
12.     new CacheService(sp.GetRequiredService<IUserService>()));
13. 
14. // [BREAKING CHANGE 2 — SocketsHttpHandler] .NET 9 HttpClientFactory uses
15. // SocketsHttpHandler as the default primary handler. The previous cast to
16. // HttpClientHandler throws InvalidCastException at runtime.
17. // Fix: use ConfigurePrimaryHttpMessageHandler with an explicit handler.
18. builder.Services.AddHttpClient("api")
19.     .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler
20.     {
21.         UseCookies = false
22.     });
23. 
24. // [BREAKING CHANGE 3 — Header redaction] .NET 9 HttpClientFactory now redacts
25. // ALL header values in Trace-level logs by default. To keep visibility into the
26. // non-sensitive headers you were logging for debugging, allowlist them explicitly.
27. builder.Services.ConfigureHttpClientDefaults(b =>
28.     b.RedactLoggedHeaders(header =>
29.         header != "X-Request-Id"
30.         && header != "X-Forwarded-For"
31.         && header != "X-Forwarded-Proto"));
32. 
33. // [BREAKING CHANGE 4 — Forwarded Headers] .NET 9 ForwardedHeadersMiddleware
34. // ignores X-Forwarded-* headers from proxies not in KnownProxies/KnownNetworks.
35. // Add your reverse-proxy IP addresses so headers are processed.
36. builder.Services.Configure<ForwardedHeadersOptions>(options =>
37. {
38.     options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
39.     options.KnownProxies.Add(IPAddress.Parse("127.0.0.1"));
40. });
41. 
42. var app = builder.Build();
43. app.UseForwardedHeaders();
44. app.Run();
45. 
